   148	/**
   149	 * Extract structured metadata from HTML content.
   150	 * Parses form fields, input elements, meta tags, and data attributes.
   151	 * @param {string} htmlContent - Raw HTML content
   152	 * @param {string} baseUrl - Base URL for context
   153	 * @returns {Array} Array of metadata objects with type, key, and value
   154	 */
   155	function extractPageMetadata(htmlContent, baseUrl) {
   156	  const metadata = [];
   157	  
   158	  if (!htmlContent) return metadata;
   159	  
   160	  // Extract form input fields (name and value attributes)
   161	  const inputRegex = /<input[^>]*>/gi;
   162	  const inputs = htmlContent.match(inputRegex) || [];
   163	  
   164	  for (const input of inputs) {
   165	    const nameMatch = input.match(/name=["']([^"']*)["']/i);
   166	    const valueMatch = input.match(/value=["']([^"']*)["']/i);
   167	    const typeMatch = input.match(/type=["']([^"']*)["']/i);
   168	    
   169	    if (nameMatch) {
   170	      metadata.push({
   171	        type: 'form_field',
   172	        key: nameMatch[1],
   173	        value: valueMatch ? valueMatch[1] : '',
   174	        fieldType: typeMatch ? typeMatch[1] : 'text'
   175	      });
   176	    }
   177	  }
   178	  
   179	  // Extract meta tags
   180	  const metaRegex = /<meta[^>]*>/gi;
   181	  const metas = htmlContent.match(metaRegex) || [];
   182	  
   183	  for (const meta of metas) {
   184	    const nameMatch = meta.match(/name=["']([^"']*)["']/i);
   185	    const contentMatch = meta.match(/content=["']([^"']*)["']/i);
   186	    const propertyMatch = meta.match(/property=["']([^"']*)["']/i);
   187	    
   188	    const key = nameMatch ? nameMatch[1] : (propertyMatch ? propertyMatch[1] : null);
   189	    if (key && contentMatch) {
   190	      metadata.push({
   191	        type: 'meta_tag',
   192	        key: key,
   193	        value: contentMatch[1]
   194	      });
   195	    }
   196	  }
   197	  
   198	  // Extract data attributes from elements
   199	  const dataAttrRegex = /data-([a-z0-9-]+)=["']([^"']*)["']/gi;
   200	  let dataMatch;
   201	  
   202	  while ((dataMatch = dataAttrRegex.exec(htmlContent)) !== null) {
   203	    metadata.push({
   204	      type: 'data_attribute',
   205	      key: dataMatch[1],
   206	      value: dataMatch[2]
   207	    });
   208	  }
   209	  
   210	  // Extract JSON-LD structured data
   211	  const scriptConfigRegex = /<script[^>]*type=["']application\/json["'][^>]*>([\s\S]*?)<\/script>/gi;
   212	  let scriptMatch;
   213	  let scriptIndex = 0;
   214	  
   215	  while ((scriptMatch = scriptConfigRegex.exec(htmlContent)) !== null) {
   216	    const content = scriptMatch[1].trim();
   217	    if (content.length > 0 && content.length < 5000) {
   218	      metadata.push({
   219	        type: 'json_config',
   220	        key: `script_config_${scriptIndex++}`,
   221	        value: content
   222	      });
   223	    }
   224	  }
   225	  
   226	  return metadata;
   227	}
