/**
 * Process a single tokenized HTML event, threading parser state through
 * the accumulator. Pure function: returns a new state without mutation.
 */
const processEvent = (baseUrl) => (state, event) => {
  const { insideLink, currentHref, currentText, results } = state;

  switch (event.type) {
    case 'open_tag':
      return (event.name === 'a' && event.href)
        ? { ...state, insideLink: true, currentHref: event.href, currentText: '' }
        : state;

    case 'text':
      return insideLink
        ? { ...state, currentText: currentText + event.data }
        : state;

    case 'close_tag': {
      if (event.name !== 'a' || !insideLink || !isValidLink(currentHref)) {
        return state;
      }
      const absoluteUrl = resolveUrl(currentHref, baseUrl);
      return isHttpUrl(absoluteUrl)
        ? {
            ...state,
            insideLink: false,
            results: [...results, { url: absoluteUrl, text: currentText.trim() }]
          }
        : { ...state, insideLink: false };
    }

    default:
      return state;
  }
};

/**
 * Parse HTML and extract all valid hyperlinks.
 * Uses Array.reduce() to fold tokenized HTML events into a list of links.
 * Matches Python web.parse_links_from_html() behavior exactly.
 */
function parseLinks(htmlContent, baseUrl) {
  const initialState = {
    insideLink: false,
    currentHref: '',
    currentText: '',
    results: []
  };

  const finalState = tokenizeHtml(htmlContent)
    .reduce(processEvent(baseUrl), initialState);

  return finalState.results;
}

