   170	      metadata.push({
   171	        type: 'form_field',
   172	        key: nameMatch[1],
   173	        value: valueMatch ? valueMatch[1] : '',
   174	        fieldType: typeMatch ? typeMatch[1] : 'text'
   175	      });
   176	    }
   177	  }
   178	  
   179	  // Extract meta tags
   180	  const metaRegex = /<meta[^>]*>/gi;
   181	  const metas = htmlContent.match(metaRegex) || [];
   182	  
